// ─── SUMMARY TRANSLATE PANEL ──────────────────────────────────────
// SPECIAL: Translates each bullet/heading individually so the result
// is the SAME SUMMARY STRUCTURE in the target language — not a new summary.
const LANG_NAMES = {
  en:'English',ta:'Tamil',hi:'Hindi',es:'Spanish',fr:'French',
  de:'German',zh:'Chinese',ar:'Arabic',ja:'Japanese',pt:'Portuguese',
  ru:'Russian',ko:'Korean',it:'Italian',te:'Telugu',ml:'Malayalam',kn:'Kannada'
};

// Emoji section headings in the generated summary — keep these as-is
const EMOJI_HEADINGS = ['📚','📖','🔍','💡','🎯','🔑','🌐','✨'];
const isEmojiHeading = (str) => EMOJI_HEADINGS.some(e => str.startsWith(e));

// Call translate API and extract the first translated sentence
const translateSingleText = async (text, from, to) => {
  if (!text?.trim()) return text;
  try {
    const r = await axios.post(`${API}/translate`, { text: text.trim(), from, to });
    const raw = r.data?.structured || '';
    // Structured output wraps in bullets — extract plain sentences
    const bullets = raw.split('\n').filter(l => l.startsWith('• ')).map(l => l.slice(2).trim());
    const plain   = raw.split('\n').filter(l => !l.startsWith('#') && !l.startsWith('• ') && l.trim()).map(l => l.trim());
    const result  = bullets.join(' ') || plain.join(' ') || text;
    return result.trim();
  } catch { return text; }
};

function SummaryTranslatePanel({ summaryText, onAddToNote }) {
  const [from,   setFrom]   = useState('en');
  const [to,     setTo]     = useState('ta');
  const [result, setResult] = useState('');
  const [busy,   setBusy]   = useState(false);
  const [progress, setProgress] = useState('');
  const [err,    setErr]    = useState('');
  const resultRef = useRef(null);

  const translateSummary = async () => {
    const txt = (summaryText || '').trim();
    if (!txt) { setErr('No summary to translate.'); return; }
    setBusy(true); setResult(''); setErr(''); setProgress('');

    try {
      const sections = parseSummaryToSections(txt);
      const toLangName = LANG_NAMES[to] || to.toUpperCase();
      const translatedSections = [];
      let done = 0;
      const total = sections.reduce((acc, s) => acc + s.bullets.length + (s.heading && !isEmojiHeading(s.heading) ? 1 : 0), 0);

      for (const sec of sections) {
        const ts = { heading: sec.heading, bullets: [], isH1: sec.isH1 };

        // Translate heading only if it has real text content (not just an emoji label like "📖 Overview")
        if (sec.heading && !isEmojiHeading(sec.heading)) {
          setProgress(`Translating heading "${sec.heading.slice(0,30)}…"`);
          ts.heading = await translateSingleText(sec.heading, from, to);
          done++;
          setProgress(`Translated ${done}/${total} pieces…`);
        }

        // Translate each bullet point
        for (const bullet of sec.bullets) {
          if (!bullet.trim()) continue;
          setProgress(`Translating: "${bullet.slice(0, 40)}…"`);
          const translated = await translateSingleText(bullet, from, to);
          ts.bullets.push(translated);
          done++;
          setProgress(`Translated ${done}/${total} pieces…`);
        }

        translatedSections.push(ts);
      }

      // Rebuild the same markdown structure but in target language
      let rebuilt = `# 🌐 ${toLangName} — Summary\n\n`;
      for (const sec of translatedSections) {
        if (sec.heading) {
          rebuilt += sec.isH1 ? `# ${sec.heading}\n\n` : `## ${sec.heading}\n`;
        }
        for (const b of sec.bullets) {
          rebuilt += `• ${b}\n`;
        }
        rebuilt += '\n';
      }

      setResult(rebuilt.trim());
      setProgress('');
      setTimeout(() => resultRef.current?.scrollIntoView({ behavior:'smooth', block:'nearest' }), 100);
    } catch (e) {
      setErr('Translation failed: ' + (e.response?.data?.message || e.message));
      setProgress('');
    } finally { setBusy(false); }
  };

  const swap = () => { const t = from; setFrom(to); setTo(t); setResult(''); setErr(''); setProgress(''); };
  const toLangObj = LANGS.find(l => l.code === to);

  return (
    <div className="tp tp-summary-panel">
      <div className="tp-bar">
        <span className="tp-icon">✨</span>
        <span className="tp-title">Translate Summary</span>
        <div className="tp-controls">
          <select className="tp-sel" value={from} onChange={e => { setFrom(e.target.value); setResult(''); }}>
            {LANGS.map(l => <option key={l.code} value={l.code}>{l.flag} {l.name}</option>)}
          </select>
          <button className="tp-swap" onClick={swap}>⇄</button>
          <select className="tp-sel" value={to} onChange={e => { setTo(e.target.value); setResult(''); }}>
            {LANGS.map(l => <option key={l.code} value={l.code}>{l.flag} {l.name}</option>)}
          </select>
          <button className="tp-go tp-go-summ" onClick={translateSummary} disabled={busy || !summaryText?.trim()}>
            {busy ? <><span className="spinner" />Working…</> : 'Translate Summary →'}
          </button>
        </div>
      </div>

      {progress && (
        <div className="tp-progress">
          <span className="spinner" /> {progress}
        </div>
      )}
      {err && <p className="tp-err">⚠️ {err}</p>}

      {result && (
        <div className="tp-result" ref={resultRef}>
          <div className="tp-result-bar">
            <span className="tp-result-title">{toLangObj?.flag} {toLangObj?.name} — Summary</span>
            <div className="tp-result-btns">
              <ReadBtn text={result} langCode={to} label={`🔊 ${toLangObj?.name}`} />
              {to !== 'en' && <ReadBtn text={result} langCode="en" label="🔊 English" />}
              <button onClick={() => navigator.clipboard.writeText(cleanForSpeech(result))}>📋 Copy</button>
              {onAddToNote && <button onClick={() => onAddToNote(result)}>➕ Add to Note</button>}
            </div>
          </div>
          <StructuredText text={result} />
        </div>
      )}
    </div>
  );
}

