  const notify = (type, text) => setFlash({ type, text });
  const speechToCode = (sc) => LANGS.find(l => l.speech === sc)?.code || 'en';

  const handleLogin = (u, token) => {
    setUser(u); setIsAuth(true);
    localStorage.setItem('u', JSON.stringify(u)); localStorage.setItem('t', token);
    axios.defaults.headers.common['Authorization'] = `Bearer ${token}`;
    notify('success', `Welcome, ${u.name}! 🎉`);
  };
  const handleLogout = () => {
    localStorage.clear(); delete axios.defaults.headers.common['Authorization'];
    setUser(null); setIsAuth(false); setNotes([]); resetNote();
  };

  const fetchNotes = async () => {
    try {
      setLoading(true);
      const p = new URLSearchParams();
      if (filterCat !== 'All') p.append('category', filterCat);
      if (search) p.append('search', search);
      const res = await axios.get(`${API}/notes?${p}`);
      setNotes(res.data);
    } catch(e) {
      if (e.response?.status === 401) { handleLogout(); notify('error','Session expired.'); }
      else notify('error','Failed to load notes.');
