    try {
      editId ? await axios.put(`${API}/notes/${editId}`, note) : await axios.post(`${API}/notes`, note);
      notify('success', editId ? 'Note updated! ✅' : 'Note saved! ✅');
      resetNote(); fetchNotes();
    } catch(e) {
      if (e.response?.status === 401) { handleLogout(); notify('error','Session expired.'); }
      else notify('error','Save failed.');
    }
  };

  const deleteNote = async id => {
    if (!window.confirm('Delete this note?')) return;
    try { await axios.delete(`${API}/notes/${id}`); notify('success','Deleted.'); fetchNotes(); }
    catch { notify('error','Delete failed.'); }
