  const resetNote = () => {
    setNote({ title:'', content:'', category:'General', source:'text' });
    setEditId(null); setSummary(''); setTab('text');
    setVideoFile(null); setVideoTranscript(''); setVideoStatus('');
    setScreenRecTranscript(''); setScreenRec(false); setVideoMode('upload');
    chunksRef.current = []; screenChunksRef.current = [];
    setScreenTranscript(''); setScreenStatus('');
    setAudioFile(null); setAudioTranscript('');
    try { mediaRecRef.current?.stop(); } catch(e) {}
    try { screenRecRef.current?.getTracks().forEach(t => t.stop()); } catch(e) {}
    stopAllSpeech();
  };

  const downloadNote = n => {
    const a = document.createElement('a');
    a.href = URL.createObjectURL(new Blob([n.content], { type:'text/plain' }));
    a.download = `${n.title}.txt`; a.click();
  };

  const doSummary = async () => {
    if (!note.content) { notify('error','Add content first.'); return; }
    setGenSummary(true); setSummary('');
    try {
      const res = await axios.post(`${API}/generate-summary`, { content: note.content });
      const s = res.data?.summary;
      if (s?.trim()) { setSummary(s); notify('success','Summary generated! ✨'); }
      else notify('error','Summary was empty. Add more text.');
    } catch(e) { notify('error', e.response?.data?.message || 'Summary failed.'); }
    finally { setGenSummary(false); }
