      else { setVideoStatus(''); notify('error','No transcription returned.'); }
    } catch(e) { setVideoStatus(''); notify('error','Transcription failed: '+(e.response?.data?.message||e.message)); }
    finally { setTranscribing(false); }
  };

  const startScreen = async () => {
    screenChunksRef.current = []; setScreenTranscript(''); setScreenStatus('');
    try {
      const stream = await navigator.mediaDevices.getDisplayMedia({ video:{ mediaSource:'screen' }, audio:true });
      streamRef.current = stream; setRecording(true); setNote(p => ({...p, source:'screen'}));
