      const mimeType = MediaRecorder.isTypeSupported('video/webm;codecs=vp9,opus') ? 'video/webm;codecs=vp9,opus' : 'video/webm';
      const recorder = new MediaRecorder(stream, { mimeType }); mediaRecRef.current = recorder;
      recorder.ondataavailable = e => { if (e.data?.size > 0) screenChunksRef.current.push(e.data); };
      recorder.onstop = async () => {
        setRecording(false); stream.getTracks().forEach(t => t.stop());
        if (!screenChunksRef.current.length) { notify('error','No data recorded. Make sure to share audio.'); setScreenStatus(''); return; }
        const blob = new Blob(screenChunksRef.current, { type:mimeType });
        const file = new File([blob], 'screen-audio.webm', { type:mimeType });
        screenChunksRef.current = [];
        const sizeMB = (blob.size/1024/1024).toFixed(1);
        notify('success',`Recording (${sizeMB}MB) — uploading…`); setScreenStatus(`☁️ Uploading ${sizeMB}MB…`);
        try {
          const fd = new FormData(); fd.append('file', file); fd.append('language', speechToCode(screenLang));
          const res = await axios.post(`${API}/transcribe`, fd, { headers:{'Content-Type':'multipart/form-data'}, timeout:600000 });
          if (res.data?.transcript) { setScreenTranscript(res.data.transcript); setNote(p => ({...p,content:res.data.transcript})); setScreenStatus(''); notify('success','✅ Full transcript ready!'); }
          else { setScreenStatus(''); notify('error','No transcript. Make sure audio was shared.'); }
        } catch(e) { setScreenStatus(''); notify('error','Failed: '+(e.response?.data?.message||e.message)); }
      };
      recorder.start(1000);
      stream.getVideoTracks()[0].onended = () => { if (recorder.state !== 'inactive') recorder.stop(); };
    } catch(e) {
      setRecording(false);
      if (e.name === 'NotAllowedError') notify('error','Screen sharing cancelled.');
      else notify('error','Failed: '+e.message);
    }
  };
  const stopScreen = () => {
    if (mediaRecRef.current?.state !== 'inactive') { mediaRecRef.current.stop(); setScreenStatus('⏳ Preparing upload…'); }
    else { streamRef.current?.getTracks().forEach(t => t.stop()); setRecording(false); }
  };

  const askAI = async () => {
    if (!chatIn.trim()) return;
    setChatMsgs(p => [...p, { role:'user', content:chatIn }]);
    const q = chatIn; setChatIn(''); setThinking(true);
    try {
      const res = await axios.post(`${API}/chat`, { question:q, allNotes:notes });
      setChatMsgs(p => [...p, { role:'assistant', content:res.data.response }]);
    } catch { notify('error','AI chat failed.'); }
    finally { setThinking(false); }
  };

  if (!isAuth) return <Auth onLogin={handleLogin} />;

  return (
    <div className="app">
      <aside className={`sidebar ${sidebarOpen ? 'open' : 'closed'}`}>
        <div className="sb-hd">
          {sidebarOpen && <span className="sb-brand">📚 SmartNotes</span>}
          <button className="sb-tog" onClick={() => setSidebarOpen(p => !p)}>{sidebarOpen ? '◀' : '▶'}</button>
        </div>
        <div className="sb-user">
          <div className="sb-av">{user?.name?.[0]?.toUpperCase()}</div>
          <div className="sb-ui"><p className="sb-name">{user?.name}</p><p className="sb-email">{user?.email}</p></div>
          <button className="sb-out" onClick={handleLogout}>🚪</button>
        </div>
        <div className="sb-search">
          <span className="sb-si">🔍</span>
          <input placeholder="Search notes…" value={search} onChange={e => setSearch(e.target.value)} />
        </div>
        <select className="sb-cat" value={filterCat} onChange={e => setFilterCat(e.target.value)}>
          <option value="All">📂 All Categories</option>
          {CATS.map(c => <option key={c}>{c}</option>)}
        </select>
        <button className="sb-new" onClick={resetNote}>＋ New Note</button>
        <div className="sb-list">
          {loading ? <div className="sb-load"><span className="spinner" /></div>
            : notes.length === 0 ? <p className="sb-mt">No notes yet.<br />Create your first ☝️</p>
            : notes.map(n => (
              <div key={n._id} className={`nb ${editId === n._id ? 'nb-active' : ''}`}>
                <div className="nb-top"><span className="nb-title">{n.title}</span><span className="nb-cat">{n.category}</span></div>
                <p className="nb-preview">{n.content.slice(0,65)}…</p>
                <div className="nb-acts">
                  <button onClick={() => startEdit(n)} className="na-e">✏️</button>
                  <button onClick={() => setViewNote(n)} className="na-v">👁️</button>
                  <button onClick={() => downloadNote(n)} className="na-d">⬇️</button>
                  <button onClick={() => deleteNote(n._id)} className="na-x">🗑️</button>
                </div>
              </div>
            ))}
        </div>
      </aside>

      <main className="main">
        <div className="ph">
          <h1 className="ph-title">✨ SmartNotes</h1>
          <p className="ph-sub">Capture · Transcribe · Translate · Summarise · Read Aloud</p>
        </div>

        {flash.text && (
          <div className={`flash flash-${flash.type}`}>
            <span>{flash.text}</span>
            <button onClick={() => setFlash({ type:'', text:'' })}>✕</button>
          </div>
        )}

        <div className="card">
          <div className="card-top">
            <h2 className="card-label">{editId ? '✏️ Edit Note' : '📝 New Note'}</h2>
            {editId && <button className="btn-x" onClick={resetNote}>✕ Cancel</button>}
          </div>
          <div className="fields">
            <input className="f-title" type="text" placeholder="Note title…"
              value={note.title} onChange={e => setNote(p => ({...p, title:e.target.value}))} />
            <select className="f-cat" value={note.category} onChange={e => setNote(p => ({...p, category:e.target.value}))}>
              {CATS.map(c => <option key={c}>{c}</option>)}
            </select>
          </div>

          <div className="tabs">
            {[['text','✍️','Text'],['voice','🎵','Audio'],['video','🎥','Video'],['screen','🖥️','Screen']].map(([id,ico,lbl]) => (
              <button key={id} className={`tab ${tab===id?'tab-on':''}`} onClick={() => setTab(id)}>
                <span>{ico}</span><span className="tl">{lbl}</span>
              </button>
            ))}
          </div>

          {/* ══ TEXT TAB ══ */}
          {tab === 'text' && (
            <section className="tc">
              <textarea className="ta" rows={9} placeholder="Start typing your notes here…"
                value={note.content} onChange={e => setNote(p => ({...p, content:e.target.value}))} />
              <div className="ta-actions">
                <ReadBtn text={note.content} langCode="en" label="🔊 Read Aloud" />
              </div>
              {/* Translate the original note text only */}
              <TranslatePanel sourceText={note.content} panelTitle="🌐 Translate Note"
                onAddToNote={t => setNote(p => ({...p, content:p.content+'\n\n'+t}))} />
            </section>
          )}

          {/* ══ AUDIO TAB ══ */}
          {tab === 'voice' && (
            <section className="tc">
              <div className="section-box">
                <div className="section-title">🎵 Upload Audio File for Transcription</div>
                <div className="hint">
                  Upload an audio file → choose the spoken language → press <strong>Transcribe</strong>.
                  Sent to AssemblyAI cloud — accurate text returned in 1–2 minutes.
                  <br />Supports MP3, WAV, M4A, OGG, FLAC — any quality.
                </div>
                <label className="upload">
                  <input type="file" accept="audio/*,.mp3,.wav,.m4a,.ogg,.flac"
                    onChange={e => { const f=e.target.files[0]; if(f){setAudioFile(f);setAudioTranscript('');notify('success',`"${f.name}" ready — press Transcribe.`);} }} hidden />
                  <span className="u-ico">🎵</span>
                  <span className="u-main">{audioFile ? audioFile.name : 'Click to upload audio file'}</span>
                  <span className="u-sub">MP3 · WAV · M4A · OGG · FLAC · up to 100 MB</span>
                </label>
                {audioFile && (
                  <div className="ctrl">
                    <div className="lg">
                      <label>Language spoken in audio</label>
                      <select value={audioLang} onChange={e => setAudioLang(e.target.value)}>
                        {LANGS.map(l => <option key={l.speech} value={l.speech}>{l.flag} {l.name}</option>)}
                      </select>
                    </div>
                    {!transcribingAudio
                      ? <button className="rbtn" onClick={transcribeAudioFile}>▶ Transcribe Audio</button>
                      : <button className="rbtn rbtn-on" onClick={() => { audioRef.current?.cancel?.(); setTranscribingAudio(false); }}><span className="dot" /> Cancel</button>}
                    {transcribingAudio && <span className="live">🔴 Transcribing…</span>}
                  </div>
                )}
                {audioTranscript && (
                  <div className="tbox">
                    <div className="tbox-hd">
                      <span>📝 Audio Transcript</span>
                      <div className="tbox-acts">
                        <ReadBtn text={audioTranscript} langCode={speechToCode(audioLang)} label="🔊 Read" />
                        <button onClick={() => setNote(p => ({...p, content:audioTranscript}))}>➕ Use as Note</button>
                      </div>
                    </div>
                    <p className="tbox-text">{audioTranscript}</p>
                  </div>
                )}
              </div>
              <textarea className="ta" rows={7} placeholder="Transcription appears here…"
                value={note.content} onChange={e => setNote(p => ({...p, content:e.target.value}))} />
              <div className="ta-actions">
                <ReadBtn text={note.content} langCode={speechToCode(audioLang)} label={`🔊 Read (${LANGS.find(l=>l.speech===audioLang)?.name})`} />
                <ReadBtn text={note.content} langCode="en" label="🔊 Read (English)" />
              </div>
              <TranslatePanel sourceText={note.content} panelTitle="🌐 Translate Transcript"
                onAddToNote={t => setNote(p => ({...p, content:p.content+'\n\n'+t}))} />
            </section>
          )}

          {/* ══ VIDEO TAB ══ */}
          {tab === 'video' && (
            <section className="tc">
              <div className="mode-switch">
                <button className={`mode-btn ${videoMode==='upload'?'mode-on':''}`} onClick={() => setVideoMode('upload')}>📁 Upload Video</button>
                <button className={`mode-btn ${videoMode==='screen'?'mode-on':''}`} onClick={() => { setVideoMode('screen'); setVideoFile(null); }}>🖥️ Record Screen</button>
              </div>
              {videoMode === 'upload' && (
                <div className="section-box">
                  <div className="section-title">📁 Upload Video File</div>
                  <div className="hint">Upload a video → select the spoken language → press <strong>Transcribe</strong>. Audio extracted and sent to AssemblyAI (2–5 min).</div>
                  <label className="upload">
                    <input type="file" accept="video/*,audio/*" onChange={handleVideoUpload} hidden />
                    <span className="u-ico">📹</span>
                    <span className="u-main">{videoFile ? videoFile.name : 'Click to upload video or audio'}</span>
                    <span className="u-sub">MP4 · MOV · AVI · WebM · MP3 · WAV</span>
                  </label>
                  {videoFile && (
                    <>
                      {videoFile.type.startsWith('video') && <video ref={videoEl} className="vid" controls src={URL.createObjectURL(videoFile)} />}
                      <div className="ctrl">
                        <div className="lg">
                          <label>Language spoken in video</label>
                          <select value={videoLang} onChange={e => setVideoLang(e.target.value)}>
                            {LANGS.map(l => <option key={l.speech} value={l.speech}>{l.flag} {l.name}</option>)}
                          </select>
                        </div>
                        {!transcribing
                          ? <button className="rbtn" onClick={startVideoTranscribe}>▶ Transcribe</button>
                          : <button className="rbtn rbtn-on" onClick={() => setTranscribing(false)}><span className="dot" /> Stop</button>}
                        {transcribing && <span className="live">🔴 Processing…</span>}
                      </div>
                      {videoStatus && <div className="vstatus">{videoStatus}</div>}
                      {videoTranscript && (
                        <div className="tbox">
                          <div className="tbox-hd"><span>📝 Video Transcript</span>
                            <div className="tbox-acts">
                              <ReadBtn text={videoTranscript} langCode={speechToCode(videoLang)} label="🔊 Read" />
                              <button onClick={() => setNote(p => ({...p,content:videoTranscript}))}>➕ Use as Note</button>
                            </div>
                          </div>
                          <p className="tbox-text">{videoTranscript}</p>
                        </div>
                      )}
                    </>
                  )}
                </div>
              )}
              {videoMode === 'screen' && (
                <div className="section-box">
                  <div className="section-title">🖥️ Record Screen + Transcribe Audio</div>
                  <div className="hint">
                    <strong>How it works:</strong>
                    <ol style={{marginTop:'.4rem',paddingLeft:'1.25rem',lineHeight:2}}>
                      <li>Select the spoken language below</li>
                      <li>Click <strong>Start Recording</strong></li>
                      <li>Choose screen/tab to share</li>
                      <li>✅ <strong>Tick "Share tab audio"</strong> in Chrome's dialog</li>
                      <li>Navigate to your content — audio is captured</li>
                      <li>Come back → click <strong>Stop Recording</strong></li>
                    </ol>
                    <span className="warn">⚠️ Must tick "Share audio" in Chrome's dialog!</span>
                  </div>
                  {screenRec && <div className="rec-status"><span className="rec-dot-lg" />Recording… Come back and click Stop when done.</div>}
                  {videoStatus && <div className="vstatus">{videoStatus}</div>}
                  <div className="ctrl">
                    <div className="lg">
                      <label>Language spoken in recording</label>
                      <select value={videoLang} onChange={e => setVideoLang(e.target.value)} disabled={screenRec}>
                        {LANGS.map(l => <option key={l.speech} value={l.speech}>{l.flag} {l.name}</option>)}
                      </select>
                    </div>
                    {!screenRec ? <button className="rbtn" onClick={startScreenRecord}>🖥️ Start Recording</button>
                      : <button className="rbtn rbtn-on" onClick={stopScreenRecord}><span className="dot" /> Stop Recording</button>}
                    {screenRec && <span className="live">🔴 Recording</span>}
                  </div>
                  {screenRecTranscript && (
                    <div className="tbox">
                      <div className="tbox-hd"><span>📝 Screen Recording Transcript</span>
                        <div className="tbox-acts">
                          <ReadBtn text={screenRecTranscript} langCode={speechToCode(videoLang)} label="🔊 Read" />
                          <button onClick={() => setNote(p => ({...p,content:screenRecTranscript}))}>➕ Use as Note</button>
                          <button onClick={() => setScreenRecTranscript('')}>🗑️ Clear</button>
                        </div>
                      </div>
                      <p className="tbox-text">{screenRecTranscript}</p>
                    </div>
                  )}
                </div>
              )}
              <textarea className="ta" rows={6} placeholder="Transcript appears here…"
                value={note.content} onChange={e => setNote(p => ({...p,content:e.target.value}))} />
              <div className="ta-actions">
                <ReadBtn text={note.content} langCode={speechToCode(videoLang)} label={`🔊 Read (${LANGS.find(l=>l.speech===videoLang)?.name})`} />
                <ReadBtn text={note.content} langCode="en" label="🔊 Read (English)" />
              </div>
              <TranslatePanel sourceText={note.content||videoTranscript||screenRecTranscript} panelTitle="🌐 Translate Transcript"
                onAddToNote={t => setNote(p => ({...p,content:p.content+'\n\n'+t}))} />
            </section>
          )}

          {/* ══ SCREEN TAB ══ */}
          {tab === 'screen' && (
            <section className="tc">
              <div className="hint">
                💡 Select language → <strong>Start Recording</strong> → share screen → navigate to video →
                come back → <strong>Stop &amp; Transcribe</strong>
                <br /><span className="warn">⚠️ Tick <strong>"Also share tab audio"</strong> in Chrome's dialog.</span>
              </div>
              <div className="ctrl">
                <div className="lg">
                  <label>Spoken language</label>
                  <select value={screenLang} onChange={e => setScreenLang(e.target.value)} disabled={recording}>
                    {LANGS.map(l => <option key={l.speech} value={l.speech}>{l.flag} {l.name}</option>)}
                  </select>
                </div>
                {!recording ? <button className="rbtn" onClick={startScreen}>🖥️ Start Recording</button>
                  : <button className="rbtn rbtn-on" onClick={stopScreen}><span className="dot" /> Stop &amp; Transcribe</button>}
                {recording && <span className="live">🔴 RECORDING</span>}
              </div>
              {recording && <div className="rec-status"><span className="rec-dot-lg" />Recording — navigate to your video. Come back and click <strong>Stop &amp; Transcribe</strong>.</div>}
              {screenStatus && <div className="vstatus">{screenStatus}</div>}
              {screenTranscript && (
                <div className="tbox">
                  <div className="tbox-hd"><span>📝 Full Transcript (AssemblyAI)</span>
                    <div className="tbox-acts">
                      <ReadBtn text={screenTranscript} langCode={speechToCode(screenLang)} label="🔊 Read" />
                      <ReadBtn text={screenTranscript} langCode="en" label="🔊 Read (En)" />
                      <button onClick={() => setNote(p => ({...p,content:screenTranscript}))}>➕ Use</button>
                      <button onClick={() => { setScreenTranscript(''); setNote(p => ({...p,content:''})); }}>🗑️</button>
                    </div>
                  </div>
                  <p className="tbox-text">{screenTranscript}</p>
                </div>
              )}
              <textarea className="ta" rows={8} placeholder="Full transcript appears here after stopping… ✨"
                value={note.content} onChange={e => setNote(p => ({...p,content:e.target.value}))} />
              <div className="ta-actions">
                <ReadBtn text={note.content} langCode={speechToCode(screenLang)} label={`🔊 Read (${LANGS.find(l=>l.speech===screenLang)?.name})`} />
                <ReadBtn text={note.content} langCode="en" label="🔊 Read (English)" />
              </div>
              <TranslatePanel sourceText={note.content||screenTranscript} panelTitle="🌐 Translate Transcript"
                onAddToNote={t => setNote(p => ({...p,content:p.content+'\n\n'+t}))} />
            </section>
          )}

          <div className="bot-bar">
            <button className="ab" onClick={doSummary} disabled={!note.content||genSummary}>
              {genSummary ? <><span className="spinner" />Generating…</> : '✨ Smart Summary'}
            </button>
            <button className="ab ab-save" onClick={saveNote}>💾 {editId ? 'Update' : 'Save Note'}</button>
          </div>

          {/* ══ SUMMARY PANEL with TWO SEPARATE TRANSLATE OPTIONS ══ */}
          {summary && (
            <div className="result-panel" ref={summaryRef}>
              <div className="rp-hd">
                <div className="rp-hd-left">
                  <span className="rp-ico">✨</span>
                  <h3>Smart Summary</h3>
                </div>
                <div className="rp-hd-right">
                  <ReadBtn text={summary} langCode="en" label="🔊 Read" className="rp-read" />
                  <button onClick={() => setNote(p => ({...p,content:summary}))}>➕ Use as Note</button>
                  <button onClick={() => navigator.clipboard.writeText(cleanForSpeech(summary))}>📋 Copy</button>
                  <button className="rp-close" onClick={() => setSummary('')}>✕</button>
                </div>
              </div>

              <StructuredText text={summary} />

              {/* ── DUAL TRANSLATION ZONE ──
                  Two clearly labelled panels side-by-side (stacked on mobile):
                  Left  → Translate ORIGINAL note text (plain text → translation)
                  Right → Translate THIS SUMMARY (section-by-section, preserves structure)
              */}
              <div className="dual-translate">

                <div className="dual-translate-col">
                  <div className="dual-translate-label">
                    <span className="dt-badge dt-badge-original">📄 Original Note</span>
                    Translate the original note text
                  </div>
                  <TranslatePanel
                    sourceText={note.content}
                    panelTitle="🌐 Translate Original"
                    onAddToNote={t => setNote(p => ({...p,content:p.content+'\n\n'+t}))}
                  />
                </div>

                <div className="dual-translate-col">
                  <div className="dual-translate-label">
                    <span className="dt-badge dt-badge-summary">✨ This Summary</span>
                    Translate the summary (keeps all sections &amp; structure)
                  </div>
                  <SummaryTranslatePanel
                    summaryText={summary}
                    onAddToNote={t => setNote(p => ({...p,content:p.content+'\n\n'+t}))}
                  />
                </div>

              </div>
            </div>
          )}
        </div>

        <button className="cfab" onClick={() => setChatOpen(p => !p)}>💬</button>

        {chatOpen && (
          <div className="cpanel">
            <div className="cp-hd"><span>🤖 AI Assistant</span><button onClick={() => setChatOpen(false)}>✕</button></div>
            <div className="cp-body">
              {chatMsgs.length === 0
                ? <div className="cp-empty">
                    <p>👋 Ask me about your notes!</p>
                    {['How many notes?','What categories?','Summarize notes'].map(s => (
                      <button key={s} className="cp-sug" onClick={() => setChatIn(s)}>{s}</button>
                    ))}
                  </div>
                : chatMsgs.map((m,i) => <div key={i} className={`cm ${m.role}`}><div className="cb">{m.content}</div></div>)}
              {thinking && <div className="cm assistant"><div className="cb"><div className="dots"><span /><span /><span /></div></div></div>}
              <div ref={chatEnd} />
            </div>
            <div className="cp-ft">
              <input placeholder="Ask about your notes…" value={chatIn}
                onChange={e => setChatIn(e.target.value)} onKeyPress={e => e.key==='Enter'&&askAI()} />
              <button onClick={askAI} disabled={!chatIn.trim()}>➤</button>
            </div>
          </div>
        )}
      </main>

      {viewNote && (
        <div className="overlay" onClick={() => setViewNote(null)}>
          <div className="modal" onClick={e => e.stopPropagation()}>
            <div className="modal-hd">
              <div>
                <h2>{viewNote.title}</h2>
                <div className="modal-tags"><span className="tag">{viewNote.category}</span><span className="tag t2">{viewNote.source}</span></div>
              </div>
              <button onClick={() => setViewNote(null)}>✕</button>
            </div>
            <div className="modal-body">
              <div className="modal-text">{viewNote.content}</div>
              <div className="modal-acts">
                <ReadBtn text={viewNote.content} langCode="en" label="🔊 Read" />
                <button onClick={() => downloadNote(viewNote)}>⬇️ Download</button>
                <button onClick={() => { startEdit(viewNote); setViewNote(null); }}>✏️ Edit</button>
                <button className="del" onClick={() => { deleteNote(viewNote._id); setViewNote(null); }}>🗑️ Delete</button>
              </div>
              <TranslatePanel sourceText={viewNote.content} panelTitle="🌐 Translate Note"
                onAddToNote={t => { setNote(p => ({...p,content:t})); setViewNote(null); notify('success','Translation loaded in editor!'); }} />
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
